        if config.enableNSLog {
            NSLog("%@", rendered)
        }
        if config.enablePrint {
            print(rendered)
        }
    }

    private func render(
        level: AnalyticsLogLevel,
        category: AnalyticsEventCategory,
        message: String,
        metadata: [String: Any?],
        file: String,
        line: Int
    ) -> String {
        var parts: [String] = []
        if config.includeTimestamps {
            parts.append(Self.iso8601Now())
        }
        parts.append("[\(category.rawValue)]")
        parts.append("[\(levelString(level))]")
        parts.append(message)

        if config.includeFileLine {
            parts.append("(\(file):\(line))")
        }

        let mdString = renderMetadata(metadata)
        if !mdString.isEmpty {
            parts.append(mdString)
        }

        return parts.joined(separator: " ")
    }

    private func renderMetadata(_ metadata: [String: Any?]) -> String {
        guard !metadata.isEmpty else { return "" }
        let pairs = metadata
            .sorted(by: { $0.key < $1.key })
            .compactMap { key, value -> String? in
                guard let value else { return nil }
                return "\(key)=\(stringify(value))"
            }
        guard !pairs.isEmpty else { return "" }
        return "{ " + pairs.joined(separator: ", ") + " }"
    }

    private func levelString(_ level: AnalyticsLogLevel) -> String {
        switch level {
        case .off: return "OFF"
        case .error: return "ERROR"
        case .warn: return "WARN"
        case .info: return "INFO"
        case .debug: return "DEBUG"
        case .verbose: return "VERBOSE"
