    }

    private func stringify(_ value: Any) -> String {
        if let s = value as? String { return truncateIfNeeded(s) }
        if let n = value as? NSNumber { return n.stringValue }
        if let b = value as? Bool { return b ? "true" : "false" }
        if let url = value as? URL { return url.absoluteString }
        if let dict = value as? [String: Any] { return truncateIfNeeded(Self.jsonString(dict) ?? "\(dict)") }
        if let dict = value as? [String: Any?] { return truncateIfNeeded(Self.jsonString(Self.compactDict(dict)) ?? "\(dict)") }
        if let arr = value as? [Any] { return truncateIfNeeded(Self.jsonString(arr) ?? "\(arr)") }
        if let data = value as? Data { return truncateIfNeeded(Self.dataPreview(data)) }
        return truncateIfNeeded(String(describing: value))
    }

    private func truncateIfNeeded(_ s: String) -> String {
        guard s.count > config.maxPayloadChars else { return s }
        let idx = s.index(s.startIndex, offsetBy: config.maxPayloadChars)
        return String(s[..<idx]) + "…(truncated)"
    }

    private func sanitizeHeaders(_ headers: [String: String]) -> [String: String] {
        var out: [String: String] = [:]
        for (k, v) in headers {
            if isSensitiveKey(k) {
                out[k] = secret(v, label: k)
            } else {
                out[k] = truncateIfNeeded(v)
            }
        }
        return out
    }

    private func sanitizeHeaderBag(_ headers: [AnyHashable: Any]) -> [String: String] {
        var out: [String: String] = [:]
        for (kAny, vAny) in headers {
            let k = String(describing: kAny)
            let v = String(describing: vAny)
            if isSensitiveKey(k) {
                out[k] = secret(v, label: k)
            } else {
                out[k] = truncateIfNeeded(v)
            }
        }
        return out
    }

    private func sanitizePayload(_ payload: Any) -> Any {
        if let dict = payload as? [String: Any] {
            return sanitizeDictionary(dict)
        }
        if let dict = payload as? [String: Any?] {
            return sanitizeDictionary(Self.compactDict(dict))
        }
        if let data = payload as? Data {
            return sanitizeData(data)
        }
        if let s = payload as? String {
            return sanitizeStringPayload(s)
        }
        if let arr = payload as? [Any] {
            return arr.map { sanitizeValue($0, keyHint: nil) }
        }
        return sanitizeValue(payload, keyHint: nil)
    }

    private func sanitizeDictionary(_ dict: [String: Any]) -> [String: Any] {
        var out: [String: Any] = [:]
        for (k, v) in dict {
            out[k] = sanitizeValue(v, keyHint: k)
        }
        return out
    }

    private func sanitizeValue(_ value: Any?, keyHint: String?) -> Any? {
        guard let value else { return nil }
        let key = keyHint?.lowercased() ?? ""
        if isSensitiveKey(key) {
            if let s = value as? String { return secret(s, label: keyHint ?? "value") }
            if let n = value as? NSNumber { return secret(n.stringValue, label: keyHint ?? "value") }
            return "<redacted>"
        }

        if key.contains("email"), let s = value as? String { return pii(s, label: keyHint ?? "email") }
        if key.contains("user"), let s = value as? String { return pii(s, label: keyHint ?? "user") }
        if key.contains("phone"), let s = value as? String { return pii(s, label: keyHint ?? "phone") }

        if let dict = value as? [String: Any] { return sanitizeDictionary(dict) }
        if let dict = value as? [String: Any?] { return sanitizeDictionary(Self.compactDict(dict)) }
        if let arr = value as? [Any] { return arr.map { sanitizeValue($0, keyHint: nil) as Any } }
        if let data = value as? Data { return sanitizeData(data) }
        if let s = value as? String { return truncateIfNeeded(s) }
        return value
    }

    private func sanitizeData(_ data: Data) -> String {
        // Never log raw binary or full JSON blobs; provide size + preview.
        return "<data bytes=\(data.count) preview=\(truncateIfNeeded(Self.dataPreview(data)))>"
    }

    private func sanitizeStringPayload(_ s: String) -> String {
        // If looks like JSON, try to parse and sanitize.
        let trimmed = s.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.hasPrefix("{") || trimmed.hasPrefix("[") {
            if let data = trimmed.data(using: .utf8),
               let obj = try? JSONSerialization.jsonObject(with: data, options: []),
               let sanitized = sanitizePayload(obj) as? Any {
                return truncateIfNeeded(Self.jsonString(sanitized) ?? truncateIfNeeded(trimmed))
            }
        }
        return truncateIfNeeded(trimmed)
    }

    private func isSensitiveKey(_ key: String) -> Bool {
        let k = key.lowercased()
        return k.contains("password")
            || k.contains("passcode")
            || k.contains("token")
            || k.contains("authorization")
            || k == "auth"
            || k.contains("secret")
            || k.contains("session")
            || k.contains("cookie")
            || k.contains("set-cookie")
            || k.contains("apikey")
            || k.contains("api_key")
            || k.contains("access_key")
            || k.contains("private")
            || k.contains("ssn")
            || k.contains("credit")
            || k.contains("card")
    }

    private func secret(_ value: String?, label: String) -> String {
        guard let value, !value.isEmpty else { return "nil" }
        if !config.redactSensitive { return truncateIfNeeded(value) }
        return "<redacted:\(label) len=\(value.count) sha256=\(Self.sha256Hex(value))>"
    }

    private func pii(_ value: String?, label: String) -> String {
        guard let value, !value.isEmpty else { return "nil" }
        if !config.redactSensitive { return truncateIfNeeded(value) }

        switch piiMode {
        case .redact:
            return "<redacted:\(label) sha256=\(Self.sha256Hex(value))>"
        case .hash:
            return "<hashed:\(label) sha256=\(Self.sha256Hex(value))>"
        case .allowInDebugOnly:
            #if DEBUG
            return truncateIfNeeded(value)
            #else
            return "<redacted:\(label) sha256=\(Self.sha256Hex(value))>"
            #endif
        }
    }

    private func errorDescription(_ error: Error) -> [String: Any] {
        let ns = error as NSError
        var dict: [String: Any] = [
            "domain": ns.domain,
            "code": ns.code,
            "description": ns.localizedDescription
        ]
        if !ns.userInfo.isEmpty {
            dict["userInfo"] = sanitizeDictionary(ns.userInfo.mapValues { $0 })
        }
        return dict
    }

    private static func iso8601Now() -> String {
        let f = ISO8601DateFormatter()
        f.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return f.string(from: Date())
    }

    private static func dataPreview(_ data: Data) -> String {
        if let s = String(data: data, encoding: .utf8) {
            return s
        }
        return data.prefix(64).map { String(format: "%02x", $0) }.joined()
    }

    private static func jsonString(_ obj: Any) -> String? {
        guard JSONSerialization.isValidJSONObject(obj) else { return nil }
        let data = try? JSONSerialization.data(withJSONObject: obj, options: [.sortedKeys])
        guard let data else { return nil }
        return String(data: data, encoding: .utf8)
    }

    private static func compactDict(_ dict: [String: Any?]) -> [String: Any] {
        var out: [String: Any] = [:]
        out.reserveCapacity(dict.count)
        for (k, v) in dict {
            if let v { out[k] = v }
        }
        return out
    }

    private static func sha256Hex(_ s: String) -> String {
        if #available(iOS 13.0, *) {
            return SHA256.hash(data: Data(s.utf8)).hexString
        } else {
            return String(s.hashValue)
        }
    }
}

