// MARK: - URLSession Instrumentation

public final class AnalyticsURLProtocol: URLProtocol {
    private static let handledKey = "AnalyticsURLProtocolHandled"
    public static var isEnabled: Bool = false

    public override class func canInit(with request: URLRequest) -> Bool {
        guard isEnabled else { return false }
        if URLProtocol.property(forKey: handledKey, in: request) != nil { return false }
        return true
    }

    public override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        request
    }

    private var task: URLSessionDataTask?
    private var startTime: CFAbsoluteTime = 0
    private var correlationId: String = UUID().uuidString
    private var receivedData = Data()

    public override func startLoading() {
        startTime = CFAbsoluteTimeGetCurrent()

        var req = request
        URLProtocol.setProperty(true, forKey: Self.handledKey, in: &req)

        let method = req.httpMethod ?? "GET"
        let url = req.url
        let headers = req.allHTTPHeaderFields
        let body: Any? = {
            if let data = req.httpBody { return data }
            return nil
        }()

        correlationId = AnalyticsDebug.shared.apiRequestStart(
            name: "URLSession",
            url: url,
            method: method,
            headers: headers,
            body: body,
            correlationId: correlationId,
            userId: nil
        )

        let session = URLSession(configuration: .default, delegate: nil, delegateQueue: nil)
        task = session.dataTask(with: req) { [weak self] data, response, error in
            guard let self else { return }
            if let data { self.receivedData.append(data) }

            let durationMs = Int((CFAbsoluteTimeGetCurrent() - self.startTime) * 1000.0)
            let http = response as? HTTPURLResponse
            let status = http?.statusCode

            if let error {
                AnalyticsDebug.shared.apiRequestError(
                    name: "URLSession",
                    correlationId: self.correlationId,
                    error: error,
                    statusCode: status,
                    responseBody: self.receivedData,
                    durationMs: durationMs
                )
                self.client?.urlProtocol(self, didFailWithError: error)
                return
            }

            if let response {
                self.client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
            }
            if let data {
                self.client?.urlProtocol(self, didLoad: data)
            }

            AnalyticsDebug.shared.apiRequestFinish(
                name: "URLSession",
                correlationId: self.correlationId,
                statusCode: status,
                responseHeaders: http?.allHeaderFields,
                responseBody: self.receivedData,
                durationMs: durationMs
            )

            self.client?.urlProtocolDidFinishLoading(self)
        }
        task?.resume()
    }

    public override func stopLoading() {
        task?.cancel()
        task = nil
    }
}

// MARK: - Usage Helpers

public enum AnalyticsDebugBootstrap {
    public static func enableNetworkInstrumentation() {
        AnalyticsURLProtocol.isEnabled = true
        URLProtocol.registerClass(AnalyticsURLProtocol.self)
    }

    public static func disableNetworkInstrumentation() {
        AnalyticsURLProtocol.isEnabled = false
        URLProtocol.unregisterClass(AnalyticsURLProtocol.self)
    }
}